INSERT IGNORE INTO payment (
payment_id, order_id, sku_id, qty, status, create_time, update_time
) VALUES (
#{paymentId}, #{orderId}, #{skuId}, #{qty}, 'PAY_INIT', NOW(), NOW()
)

mapper.update:
UPDATE payment
SET refund_retry_count = refund_retry_count + 1
WHERE order_id = #{orderId}
AND payment_id = #{paymentId}
AND status = 'REFUND_FAIL'
AND refund_retry_count  <  #{maxRetry}

UPDATE payment
SET status = 'REFUND_FAIL_MAX_RETRY'
WHERE order_id = #{orderId}
AND payment_id = #{paymentId}
AND refund_retry_count >= #{maxRetry}

UPDATE payment
SET pay_retry_count = pay_retry_count + 1
WHERE order_id = #{orderId}
AND status = 'PAY_FAIL'
AND pay_retry_count  <  #{maxRetry}

UPDATE payment
SET status = 'PAY_FAIL_MAX_RETRY'
WHERE order_id = #{orderId}
AND pay_retry_count >= #{maxRetry}
